mapper.select:
SELECT * FROM tutor_document
WHERE user_id = #{userId}
ORDER BY created_at DESC

mapper.insert:
INSERT INTO tutor_document (
    id, user_id, doc_type, file_size, original_name, store_name, file_path, content_type
) VALUES (
    UUID(), #{userId}, #{docType}, #{fileSize}, #{originalName}, #{storeName}, #{filePath}, #{contentType}
)

mapper.update:
UPDATE tutor_document
SET doc_type = #{docType}, file_path = #{filePath}
WHERE id = #{id}

mapper.delete:
DELETE FROM tutor_document
WHERE user_id = #{userId}
  AND doc_type = #{docType}

mapper.update:
UPDATE tutor_document
SET reviewed_by = #{reviewedBy}, reviewed_at = NOW()
WHERE id = #{id}

UPDATE tutor_document
SET reviewed_by = #{reviewedBy}, reviewed_at = NOW(), reject_reason = #{rejectReason}
WHERE id = #{id}
